import React, { useState } from 'react';
import MinimalistInput from './components/MinimalistInput';
import MinimalistButton from './components/MinimalistButton';
import DisclaimerModal from './components/DisclaimerModal';
import IntakeForm from './components/IntakeForm';
import Dashboard from './components/Dashboard';

type Step = 'login' | 'disclaimer' | 'intake' | 'dashboard';

const App: React.FC = () => {
  const [step, setStep] = useState<Step>('login');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const [userData, setUserData] = useState({ name: '' });

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === '12345') {
      setStep('disclaimer');
    } else {
      setError(true);
      setTimeout(() => setError(false), 3000);
    }
  };

  const onAcknowledge = () => setStep('intake');

  const onIntakeComplete = (data: { name: string }) => {
    setUserData(data);
    setStep('dashboard');
  };

  return (
    <div className="flex flex-col items-center min-h-screen">
      <header className="w-full pt-12 pb-8 flex justify-center z-50">
        <h1 className="text-2xl md:text-3xl font-serif tracking-[0.4em] uppercase font-light text-cream opacity-90">
          PILOT MEDICAL GROUP
        </h1>
      </header>

      <main className="w-full flex-grow flex flex-col items-center px-6 pb-20 max-w-6xl">
        {step === 'login' && (
          <section className="animate-in fade-in slide-in-from-bottom-2 duration-700 flex flex-col items-center justify-center w-full max-w-md pt-20">
            <div className="w-full space-y-12 text-center">
              <div className="space-y-4">
                <p className="font-sans text-[10px] tracking-[0.4em] uppercase opacity-50">Private AI Healthcare Portal</p>
                <h2 className="text-xl font-serif italic">Access Verification</h2>
              </div>
              <form onSubmit={handleLogin} className="space-y-8">
                <div className="relative">
                  <MinimalistInput
                    type="password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="ACCESS KEY"
                    className="text-center"
                  />
                  {error && (
                    <p className="absolute left-0 right-0 -bottom-8 text-[10px] font-sans text-red-400 tracking-widest uppercase py-2">
                      Incorrect Access Key
                    </p>
                  )}
                </div>
                <MinimalistButton type="submit" className="mt-4">ENTER</MinimalistButton>
              </form>
            </div>
          </section>
        )}

        {step === 'disclaimer' && (
          <DisclaimerModal onAcknowledge={onAcknowledge} />
        )}

        {step === 'intake' && (
          <IntakeForm onComplete={onIntakeComplete} />
        )}

        {step === 'dashboard' && (
          <Dashboard userName={userData.name} />
        )}
      </main>
    </div>
  );
};

export default App;

