        </header>

        <form onSubmit={handleSubmit} className="space-y-10">
          <div className="space-y-8">
            <div className="flex flex-col">
              <label className="text-[10px] font-sans tracking-widest uppercase opacity-40 mb-1">Full Legal Name</label>
              <MinimalistInput value={name} onChange={(e) => setName(e.target.value)} placeholder="Required" />
            </div>
            <div className="flex flex-col">
              <label className="text-[10px] font-sans tracking-widest uppercase opacity-40 mb-1">Email Address</label>
              <MinimalistInput type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Optional" />
            </div>
            <div className="flex flex-col">
              <label className="text-[10px] font-sans tracking-widest uppercase opacity-40 mb-1">Contact Number</label>
              <MinimalistInput value={phone} onChange={(e) => setPhone(e.target.value)} placeholder="Optional" />
            </div>
            <div className="flex flex-col">
              <label className="text-[10px] font-sans tracking-widest uppercase opacity-40 mb-1">Last 4 Digits NRIC</label>
